  market_investment_disclaimer_body: { ar:'هذه المعلومات لأغراض تعليمية وتحليلية فقط، وليست توصية بشراء أو بيع أي أصول استثمارية. تداول الأصول المالية ينطوي على مخاطر وقد لا يكون مناسبًا لجميع المستثمرين.', en:'This information is for educational and analytical purposes only and is not a recommendation to buy or sell any investment asset. Trading financial assets involves risk and may not be suitable for all investors.', fr:'Ces informations sont fournies à des fins éducatives et analytiques uniquement et ne constituent pas une recommandation d’achat ou de vente d’actifs. Le trading d’actifs financiers comporte des risques et peut ne pas convenir à tous les investisseurs.' },
  market_advanced_settings: { ar:'إعدادات متقدمة', en:'Advanced settings', fr:'Paramètres avancés' },
  market_calculation_method: { ar:'طريقة الحساب', en:'Calculation method', fr:'Méthode de calcul' },
  market_risk_formula: { ar:'مبلغ المخاطرة = رصيد الحساب × نسبة المخاطرة.', en:'Risk amount = account balance × risk percentage.', fr:'Montant du risque = solde du compte × pourcentage de risque.' },
  market_pips_formula: { ar:'عدد النقاط يُحسب من الفرق بين سعر الدخول وسعر الخروج حسب الزوج والاتجاه.', en:'Pips are calculated from the difference between entry and exit prices based on pair and direction.', fr:'Les pips sont calculés à partir de l’écart entre le prix d’entrée et le prix de sortie selon la paire et le sens.' },
  market_lot_formula: { ar:'حجم اللوت يعتمد على مبلغ المخاطرة ومسافة وقف الخسارة وقيمة النقطة.', en:'Lot size depends on risk amount, stop-loss distance, and pip value.', fr:'La taille du lot dépend du montant du risque, de la distance du stop loss et de la valeur du pip.' },
  market_trader_tools_disclaimer: { ar:'هذه الأدوات تعليمية وتحليلية، ولا تُعدّ توصية مالية أو استثمارية.', en:'These tools are educational and analytical only, not financial or investment advice.', fr:'Ces outils sont éducatifs et analytiques, et ne constituent pas un conseil financier ou d’investissement.' },
