  market_calendar_not_configured_body: { ar:'لا يوجد مزود بيانات مفعّل يدعم التقويم الاقتصادي في البيئة الحالية.', en:'No enabled data provider supports the economic calendar in the current environment.', fr:'Aucun fournisseur de données activé ne prend en charge le calendrier économique dans l’environnement actuel.' },
  market_calendar_access_denied_title: { ar:'التقويم الاقتصادي غير متوفر حالياً', en:'Economic calendar is currently unavailable', fr:'Le calendrier économique est actuellement indisponible' },
  market_calendar_access_denied_body: { ar:'مزود البيانات الحالي لا يملك صلاحية الوصول إلى التقويم الاقتصادي. سيتم عرض الأحداث تلقائياً عند ربط مزود يدعم هذه الخدمة.', en:'The current data provider is not entitled to access the economic calendar. Events will appear automatically when a provider that supports this service is connected.', fr:'Le fournisseur de données actuel n’a pas les droits d’accès au calendrier économique. Les événements s’afficheront automatiquement lorsqu’un fournisseur compatible sera connecté.' },
  market_calendar_rate_limited_title: { ar:'تم بلوغ حد طلبات مزود البيانات', en:'Data-provider request limit reached', fr:'Limite de requêtes du fournisseur atteinte' },
  market_calendar_rate_limited_body: { ar:'تم بلوغ حد الطلبات مؤقتاً. يتم عرض آخر بيانات ناجحة عند توفرها.', en:'The request limit was reached temporarily. Last successful data is shown when available.', fr:'La limite de requêtes a été atteinte temporairement. Les dernières données réussies sont affichées si disponibles.' },
  market_calendar_unavailable_title: { ar:'التقويم الاقتصادي غير متوفر حالياً', en:'Economic calendar is currently unavailable', fr:'Le calendrier économique est actuellement indisponible' },
  market_calendar_unavailable_body: { ar:'تعذر جلب بيانات التقويم الاقتصادي من مزود البيانات الحالي. سيتم عرض الأحداث تلقائياً عند توفر مصدر بيانات يدعم هذه الخدمة.', en:'Could not load economic calendar data from the current data provider. Events will appear automatically when a provider that supports this service is available.', fr:'Impossible de charger les données du calendrier économique depuis le fournisseur actuel. Les événements s’afficheront automatiquement lorsqu’un fournisseur compatible sera disponible.' },
  market_calendar_public_note: { ar:'سيتم عرض الأحداث فور تفعيل مصدر البيانات.', en:'Events will be shown as soon as the data source is enabled.', fr:'Les événements seront affichés dès que la source de données sera activée.' },
