  market_calendar_filter_empty_body: { ar:'جرّب فلترًا آخر أو عد لاحقًا عند توفر أحداث جديدة.', en:'Try another filter or check back when new events are available.', fr:'Essayez un autre filtre ou revenez lorsque de nouveaux événements seront disponibles.' },
