  market_instrument_type_hint: { ar:'يؤثر نوع الأداة في طريقة حساب حجم الصفقة.', en:'Instrument type affects how position size is calculated.', fr:'Le type d’instrument influence le calcul de la taille de position.' },
  market_gold_metals: { ar:'الذهب / المعادن', en:'Gold / Metals', fr:'Or / Métaux' },
